sql:
SELECT DISTINCT m.member_id, m.member_name, m.email 
FROM members m 
JOIN cpd_records r ON m.member_id = r.member_id;

SELECT activity_description, cpd_hours, activity_type, activity_date_range
FROM cpd_activities
WHERE cpd_hours = '2 CPD Hours';

SELECT admin_name 
FROM admin_users 
WHERE admin_id IN (SELECT reviewed_by FROM cpd_claims);

SELECT role, COUNT(*) 
FROM admin_users 
GROUP BY role;

SELECT * 
FROM cpd_records 
WHERE member_id = 1;

SELECT AVG(hours_claimed) AS average_claimed_hours
FROM cpd_records
WHERE date_completed BETWEEN '2023-01-01' AND '2023-12-31';

SELECT member_id, member_name
FROM members
WHERE member_id NOT IN (SELECT member_id FROM cpd_records);

SELECT COUNT(claim_id) 
FROM cpd_claims 
WHERE status = 'under review';

SELECT DISTINCT m.member_id, m.member_name
FROM members m
INNER JOIN cpd_claims cc ON m.member_id = cc.member_id;

SELECT member_id, SUM(hours_claimed) AS total_hours_claimed
FROM cpd_records
GROUP BY member_id;

SELECT * 
FROM cpd_activities 
WHERE activity_id = 1;

SELECT members.member_name, cpd_records.status
FROM members
INNER JOIN cpd_records ON members.member_id = cpd_records.member_id;
